class Solution {
public:
    long long validSubstringCount(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        long long res = 0;
        for (int i = 0; i < m; i++) {
            for (int j = i + n; j <= m; j++) {
                string s = word1.substr(i, j - i);
                int cnt1[26] = {0}, cnt2[26] = {0};
                for (char c : s) cnt1[c - 'a']++;
                for (char c : word2) cnt2[c - 'a']++;
                bool ok = true;
                for (int k = 0; k < 26; k++) {
                    if (cnt1[k] < cnt2[k]) {
                        ok = false;
                        break;
                    }
                }
                if (ok) res++;
            }
        }
        return res;
    }
};
